const input = $input.first().json;
// Aceita tanto o node de Chat nativo do n8n (campos chatInput/sessionId)
// quanto um corpo de webhook "clássico" (message/session_id), caso alguém
// prefira integrar via HTTP em vez do painel de chat.
const body = input.body || input;
const rawMessage = body.chatInput || body.domain || body.message || body.dominio || '';
const sessionId = body.sessionId || body.session_id || body.chat_id || body.id || 'sem-sessao';
const match = String(rawMessage).match(/([a-z0-9-]+\.)+[a-z]{2,}/i);
const dominio = match
  ? match[0].toLowerCase().replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/.*$/, '')
  : String(rawMessage).trim();

if (!dominio) {
  throw new Error("Não foi possível identificar um domínio na mensagem recebida.");
}

// O resto da mensagem (tudo que não é o domínio em si) costuma trazer
// contexto valioso que o vendedor digitou junto (ex.: "itau.com.br - prospect
// quer automatizar atendimento do call center"). Antes esse texto era
// descartado por completo -- só o domínio seguia adiante no pipeline, e a
// análise final nunca via essa descrição. Preservamos aqui para os nodes
// seguintes usarem.
const contexto_usuario = String(rawMessage)
  .replace(match ? match[0] : '', '')
  .replace(/^[\s\-:,]+|[\s\-:,]+$/g, '')
  .trim();

return [{ json: { dominio, url_base: `https://${dominio}`, contexto_usuario, session_id: sessionId } }];

const domainData = $('Extrair Domínio').first().json;
const siteHtml = $input.first().json.data || '';

const textoLimpo = String(siteHtml)
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .toLowerCase();

// Heurística simples (contagem de palavras-chave em português no texto do
// site) para adivinhar o setor do prospect -- não é uma classificação
// confiável por si só, serve apenas para direcionar a segunda busca do
// SearXNG para tendências de IA no setor certo, em vez de uma busca
// genérica demais para ajudar na estratégia.
const dicionarioSetores = {
  'Bancário/Financeiro': ['banco', 'crédito', 'investimento', 'financeira', 'cartão de crédito', 'empréstimo', 'conta corrente'],
  'Varejo/E-commerce': ['loja', 'varejo', 'e-commerce', 'ecommerce', 'carrinho de compras', 'frete grátis'],
  'Saúde': ['hospital', 'saúde', 'clínica', 'paciente', 'plano de saúde', 'medicina'],
  'Seguros': ['seguro', 'seguradora', 'sinistro', 'apólice'],
  'Indústria/Manufatura': ['indústria', 'fábrica', 'manufatura', 'produção industrial', 'linha de produção'],
  'Logística/Transporte': ['logística', 'transportadora', 'frete', 'rastreamento de entrega', 'transporte de cargas'],
  'Educação': ['educação', 'escola', 'curso online', 'aluno', 'universidade'],
  'Jurídico': ['advocacia', 'jurídico', 'contrato', 'escritório de advocacia'],
  'Agronegócio': ['agronegócio', 'fazenda', 'commodities', 'grãos', 'safra'],
  'Telecom': ['telecom', 'operadora', 'banda larga', 'plano de celular'],
  'Tecnologia/Software': ['software', 'saas', 'plataforma digital', 'aplicativo', 'desenvolvedor'],
};

let setorDetectado = 'Indeterminado';
let melhorContagem = 0;
for (const [setor, palavras] of Object.entries(dicionarioSetores)) {
  const contagem = palavras.reduce((acc, palavra) => acc + (textoLimpo.split(palavra).length - 1), 0);
  if (contagem > melhorContagem) {
    melhorContagem = contagem;
    setorDetectado = setor;
  }
}

const query_empresa = `${domainData.dominio} empresa notícias tecnologia inteligência artificial`;
const query_setor = setorDetectado !== 'Indeterminado'
  ? `tendências de inteligência artificial e automação no setor de ${setorDetectado} Brasil`
  : `tendências de inteligência artificial e automação para empresas Brasil`;
const query_mercado = `${domainData.dominio} concorrentes mercado posicionamento`;

return [{ json: {
  ...domainData,
  setor_detectado_heuristica: setorDetectado,
  query_empresa,
  query_setor,
  query_mercado,
} }];

const domainData = $('Extrair Domínio').first().json;
const setorData = $('Detectar Setor e Montar Queries').first().json;
const statusFinanceiro = $('Finalizar Status Financeiro').first().json;
const siteHtml = ($('Pesquisar Site do Prospect').first().json.data) || '';

// "Deep research" leve: em vez de uma única busca genérica, rodamos 3
// buscas com ângulos diferentes -- notícias da empresa, tendências de IA
// no setor dela (ajuda a validar/calibrar o direcionamento de estratégia,
// não só a classificação) e concorrência/posicionamento de mercado.
// Resultados limitados propositalmente (3+3+2, ~120-150 chars cada) para
// não estourar o tamanho do prompt -- o Gemma local é sensível a isso.
const resultadosEmpresa = ($('Buscar no SearXNG (Empresa)').first().json.results || []).slice(0, 3);
const resultadosSetor = ($('Buscar no SearXNG (Setor)').first().json.results || []).slice(0, 3);
const resultadosMercado = ($('Buscar no SearXNG (Mercado)').first().json.results || []).slice(0, 2);

const textoLimpo = String(siteHtml)
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 1200);

function resumir(resultados) {
  return resultados
    .map((r, i) => `${i + 1}. ${r.title} — ${(r.content || '').slice(0, 150)}`)
    .join('\n');
}

const perfil_pesquisa = [
  `Domínio: ${domainData.dominio}`,
  `Conteúdo do site institucional (trecho): ${textoLimpo || 'não foi possível acessar o site.'}`,
  `Notícias e sinais sobre a empresa (SearXNG):\n${resumir(resultadosEmpresa) || 'nenhum resultado relevante encontrado.'}`,
  `Tendências de IA no setor "${setorData.setor_detectado_heuristica}" (SearXNG -- setor detectado por heurística a partir do site, trate com ceticismo se parecer errado):\n${resumir(resultadosSetor) || 'nenhum resultado relevante encontrado.'}`,
  `Concorrência e posicionamento de mercado (SearXNG):\n${resumir(resultadosMercado) || 'nenhum resultado relevante encontrado.'}`,
  `Situação na bolsa de valores (B3): ${statusFinanceiro.contexto_financeiro_status}`,
].join('\n\n');

// Se o vendedor digitou um contexto de dor/necessidade específico, usamos isso
// para a busca de cases de sucesso. Caso contrário, criamos uma busca baseada
// nas tendências gerais de IA para o setor da empresa.
const dorFocada = String(domainData.contexto_usuario || '').trim() ||
  `Casos de uso de Inteligência Artificial, automação e transformação digital no setor de ${setorData.setor_detectado_heuristica}`;

return [{ json: {
  dominio: domainData.dominio,
  perfil_pesquisa,
  contexto_usuario: domainData.contexto_usuario,
  dor_usuario_focada: dorFocada,
  session_id: domainData.session_id,
  listada_b3: statusFinanceiro.listada_b3,
  ticker: statusFinanceiro.ticker,
} }];

const perfil = $('Compilar Perfil de Pesquisa').first().json;
// O input direto deste node agora vem de um Merge ("Merge Cases + Financeiro")
// que combina a busca de cases (RAG da consultoria) com a busca de trechos
// de relatórios financeiros do próprio prospect -- por isso referenciamos os
// dois nodes de origem pelo nome em vez de usar $json diretamente (que ficaria
// ambíguo sobre qual dos dois resultados é).
const qdrantResp = $('Buscar Cases Similares (Qdrant)').first().json;
const financeiroResp = $('Buscar Trechos de Relatórios (Qdrant)').first().json;
const points = (qdrantResp.result && qdrantResp.result.points) || [];
const pontosFinanceiros = (financeiroResp.result && financeiroResp.result.points) || [];

const casesTexto = points.map((p, i) => {
  const c = p.payload;
  return `Case ${i + 1} (similaridade ${p.score.toFixed(2)}): "${c.titulo}"\n`
    + `Classificação correta: ${c.classificacao_correta}\n`
    + `Sinais de diagnóstico: ${(c.sinais_diagnostico || []).slice(0, 2).join(' | ')}\n`
    + `Abordagem recomendada: ${c.abordagem_recomendada}`;
}).join('\n\n');

// Dados financeiros oficiais da CVM (Demonstração do Resultado Consolidado)
// do PRÓPRIO prospect -- não são cases da consultoria. Vieram do cadastro
// público da CVM (dados.cvm.gov.br) + upload para a coleção
// "ai_sdr_relatorios_financeiros" no Qdrant, só para empresas identificadas
// como negociadas na B3.
const trechosFinanceirosTexto = pontosFinanceiros.map((p, i) => {
  const c = p.payload;
  return `Trecho ${i + 1} (similaridade ${p.score.toFixed(2)}) -- ${c.titulo_documento || c.url || 'relatório'}:\n${c.chunk_texto}`;
}).join('\n\n');

// O parametro "format" da API do Ollama (JSON Schema) e ignorado por este
// modelo local (gemma4:12b-mlx via MLX nao aplica constrained decoding) --
// confirmado em teste manual: mesmo um schema trivial voltou embrulhado em
// ```json ... ```. Por isso o formato esperado precisa estar no PROPRIO
// texto do prompt, com um exemplo concreto para o modelo imitar, e o
// parsing final (node "Montar Resposta Final") precisa tolerar variacoes.
const exemploSaida = {
  dominio: perfil.dominio,
  perfil_empresa: {
    nome: "Nome da empresa",
    setor: "Setor de atuação",
    porte_estimado: "Grande | Média | Pequena | Indeterminado",
    resumo: "resumo de 2-3 frases",
    sinais_maturidade_digital: ["sinal 1", "sinal 2"]
  },
  classificacao: {
    tipo: "GenAI real | RPA | BI | Automação clássica | Híbrido",
    confianca: "Alta | Média | Baixa",
    justificativa: "explicação baseada nos sinais e nos cases similares"
  },
  maturidade_ia_prospect: {
    nivel: "Inicial | Em desenvolvimento | Avançado | Indeterminado",
    justificativa: "..."
  },
  direcionamento_estrategia: {
    recomendacao: "Manter abordagem proposta pelo prospect | Propor shift de estratégia | Aprofundar discovery antes de avançar",
    justificativa: "..."
  },
  perguntas_discovery: ["pergunta 1", "pergunta 2", "pergunta 3"]
};

const contextoVendedor = perfil.contexto_usuario
  ? `CONTEXTO INFORMADO PELO VENDEDOR (isto veio direto de quem está qualificando o lead -- leve em conta na sua análise e não ignore):\n${perfil.contexto_usuario}\n\n`
  : '';

const prompt = `Você é um analista de pré-vendas de uma consultoria especializada em IA. Sua tarefa é qualificar um prospect a partir da pesquisa abaixo, decidindo se a demanda dele é GenAI real, RPA, BI ou Automação clássica. A pesquisa inclui não só o site do prospect, mas também notícias sobre a empresa, tendências de IA no setor dela e concorrência/posicionamento de mercado -- use esses sinais de setor e mercado especialmente para embasar o campo "direcionamento_estrategia" e as "perguntas_discovery", não baseie a recomendação só no site institucional. Se a empresa for negociada na B3, a pesquisa também inclui dados financeiros oficiais da CVM (receita, custos, resultado) dos últimos períodos -- priorize essas informações (são dados financeiros oficiais e obrigatórios por lei) na classificação, na maturidade em IA e no direcionamento de estratégia, sempre que estiverem disponíveis.

${contextoVendedor}PESQUISA SOBRE O PROSPECT:
${perfil.perfil_pesquisa}

CASES SIMILARES DA CONSULTORIA (use como referência de diagnóstico, não copie literalmente):
${casesTexto || 'Nenhum case similar encontrado.'}

DADOS FINANCEIROS OFICIAIS DA CVM DO PRÓPRIO PROSPECT (Demonstração do Resultado Consolidado; só disponível para empresas negociadas na B3; use para embasar classificação, maturidade e estratégia quando presente):
${trechosFinanceirosTexto || 'Nenhum relatório de RI/mercado disponível para esta empresa.'}

Responda APENAS com um objeto JSON no formato do exemplo abaixo, preenchido com sua análise (troque os valores de exemplo pelos reais; os campos com "|" indicam as únicas opções válidas, escolha uma). Não escreva nada antes ou depois do JSON, e não use blocos de código (sem \`\`\`).

${JSON.stringify(exemploSaida, null, 2)}

Seja honesto: se a pesquisa não trouxe sinal suficiente, use "confianca": "Baixa" e diga isso na justificativa.`;

const cases_relevantes = points.map((p) => ({
  titulo: p.payload.titulo,
  classificacao: p.payload.classificacao_correta,
  similaridade: Math.round(p.score * 100) / 100,
  licao_aplicavel: p.payload.resultado_licao,
}));

// IMPORTANTE: o corpo da requisicao ao Ollama e montado AQUI (em JS real),
// nao na expressao ={{ }} do node HTTP Request seguinte. O parser de
// expressoes do n8n usa correspondencia nao-gulosa e para no PRIMEIRO
// '}}' que encontrar no texto do template - como o JSON Schema abaixo tem
// varias chaves de fechamento aninhadas ('}}' aparece dezenas de vezes),
// embutir isso direto numa expressao ={{ ... }} trunca o JSON no meio.
// Construindo a string aqui e so referenciando '$json.body_llm_request'
// no node seguinte, a expressao la fica trivial (um unico '}}' no final).
const outputSchema = {"type": "object", "properties": {"dominio": {"type": "string"}, "perfil_empresa": {"type": "object", "properties": {"nome": {"type": "string"}, "setor": {"type": "string"}, "porte_estimado": {"type": "string", "enum": ["Grande", "Média", "Pequena", "Indeterminado"]}, "resumo": {"type": "string"}, "sinais_maturidade_digital": {"type": "array", "items": {"type": "string"}}}, "required": ["nome", "setor", "porte_estimado", "resumo", "sinais_maturidade_digital"]}, "classificacao": {"type": "object", "properties": {"tipo": {"type": "string", "enum": ["GenAI real", "RPA", "BI", "Automação clássica", "Híbrido"]}, "confianca": {"type": "string", "enum": ["Alta", "Média", "Baixa"]}, "justificativa": {"type": "string"}}, "required": ["tipo", "confianca", "justificativa"]}, "maturidade_ia_prospect": {"type": "object", "properties": {"nivel": {"type": "string", "enum": ["Inicial", "Em desenvolvimento", "Avançado", "Indeterminado"]}, "justificativa": {"type": "string"}}, "required": ["nivel", "justificativa"]}, "direcionamento_estrategia": {"type": "object", "properties": {"recomendacao": {"type": "string", "enum": ["Manter abordagem proposta pelo prospect", "Propor shift de estratégia", "Aprofundar discovery antes de avançar"]}, "justificativa": {"type": "string"}}, "required": ["recomendacao", "justificativa"]}, "perguntas_discovery": {"type": "array", "items": {"type": "string"}, "minItems": 3, "maxItems": 5}}, "required": ["dominio", "perfil_empresa", "classificacao", "maturidade_ia_prospect", "direcionamento_estrategia", "perguntas_discovery"]};

const body_llm_request = JSON.stringify({
  model: 'gemma4:12b-mlx',
  prompt,
  format: outputSchema,
  stream: false,
});

return [{ json: { dominio: perfil.dominio, prompt, cases_relevantes, body_llm_request, session_id: perfil.session_id } }];

const montado = $('Montar Prompt').first().json;
// O node "Classificar com Gemma (Chain)" (n8n-nodes-langchain.chainLlm) devolve
// o texto gerado no campo "text" -- antes, com a chamada HTTP crua ao Ollama,
// o campo era "response". Mantemos os dois por segurança (ex.: se alguém
// reverter para o node HTTP antigo).
const textoGerado = $json.text ?? $json.response ?? '';

// O modelo local nem sempre respeita "responda so o JSON": as vezes embrulha
// em ```json ... ``` ou acrescenta texto antes/depois. Limpamos isso antes
// de tentar o parse, e so entao extraimos o primeiro objeto JSON encontrado.
function extrairJson(texto) {
  let limpo = String(texto || '')
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  const inicio = limpo.indexOf('{');
  const fim = limpo.lastIndexOf('}');
  if (inicio === -1 || fim === -1 || fim < inicio) return null;
  try {
    return JSON.parse(limpo.slice(inicio, fim + 1));
  } catch (e) {
    return null;
  }
}

const parsed = extrairJson(textoGerado);

if (!parsed) {
  const aviso = `⚠️ Não consegui interpretar a resposta do modelo para o domínio **${montado.dominio}**. Tente novamente.\n\nResposta bruta:\n${textoGerado}`;
  return [{ json: { markdown: aviso, output: aviso } }];
}

const disclaimer = 'Esta é uma recomendação gerada por IA para apoiar o direcionamento comercial. A decisão final sobre estratégia e discovery é do vendedor.';

const casesTexto = (montado.cases_relevantes || []).map((c, i) =>
  `${i + 1}. **${c.titulo}** _(${c.classificacao}, similaridade ${c.similaridade})_\n   ${c.licao_aplicavel}`
).join('\n');

// Acesso tolerante: o modelo local pode nao preencher 100% da estrutura
// esperada. Preferimos mostrar "n/d" a quebrar a resposta inteira.
const pe = parsed.perfil_empresa || {};
const cl = parsed.classificacao || {};
const mat = parsed.maturidade_ia_prospect || {};
const dir = parsed.direcionamento_estrategia || {};
const perguntas = Array.isArray(parsed.perguntas_discovery) ? parsed.perguntas_discovery : [];

const markdown = `## Qualificação — ${parsed.dominio || montado.dominio}

**Perfil da empresa:** ${pe.resumo || 'n/d'}
- Setor: ${pe.setor || 'n/d'}
- Porte estimado: ${pe.porte_estimado || 'n/d'}
- Sinais de maturidade digital: ${(pe.sinais_maturidade_digital || []).join('; ') || 'n/d'}

**Classificação:** ${cl.tipo || 'n/d'} _(confiança: ${cl.confianca || 'n/d'})_
${cl.justificativa || ''}

**Maturidade em IA do prospect:** ${mat.nivel || 'n/d'}
${mat.justificativa || ''}

**Direcionamento sugerido:** ${dir.recomendacao || dir.recomendação || 'n/d'}
${dir.justificativa || ''}

**Perguntas de discovery sugeridas:**
${perguntas.length ? perguntas.map((q) => `- ${q}`).join('\n') : 'n/d'}

**Cases relevantes da consultoria:**
${casesTexto || '_nenhum case suficientemente similar encontrado._'}

---
_${disclaimer}_`;

// "output" e o campo que o node de Chat nativo do n8n (Chat Trigger, modo
// "lastNode") usa para exibir a resposta no painel de chat. Mantemos
// "markdown" tambem por compatibilidade com quem ainda integrar via webhook.
return [{ json: { markdown, output: markdown } }];

const domainData = $('Extrair Domínio').first().json;
const siteHtml = String($input.first().json.data || '');

const matchTitle = siteHtml.match(/<title[^>]*>([^<]*)<\/title>/i);
let nomeProvavel = matchTitle ? matchTitle[1] : '';
nomeProvavel = nomeProvavel
  .replace(/&amp;/g, '&')
  .replace(/\s*[-|–].*(home|in[ií]cio|site oficial).*$/i, '')
  .replace(/\s+/g, ' ')
  .trim();
if (!nomeProvavel) {
  // Fallback: usa o próprio domínio (sem TLD) como aproximação do nome.
  nomeProvavel = domainData.dominio.split('.')[0];
}

// Busca best-effort por um CNPJ no texto do site (ex.: rodapé "CNPJ:
// XX.XXX.XXX/0001-XX"). Usado a seguir para consultar a BrasilAPI e obter a
// razão social oficial, que costuma casar melhor com o nome usado na B3 do
// que o nome de marketing do <title> -- mas pode não ser encontrado (scraping
// simples, sem JS rendering, mesma limitação já documentada no README).
const matchCnpj = siteHtml.match(/(\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2})/);
const cnpjEncontrado = matchCnpj ? matchCnpj[1].replace(/[^\d]/g, '') : '';

return [{ json: {
  ...domainData,
  nome_provavel: nomeProvavel,
  cnpj_encontrado: cnpjEncontrado,
} }];

const nomeData = $('Extrair Nome da Empresa e CNPJ').first().json;
const cnpjResp = $('Consultar CNPJ (BrasilAPI)').first().json;
const b3Data = $json; // Buscar Tickers B3 (brapi) -- input direto deste node
const b3Stocks = b3Data.stocks || [];

// Normalização tosca: maiúsculas, sem acento, remove sufixos societários
// comuns -- para comparar heuristicamente nomes de marketing/razão social
// com o nome oficial listado na B3. Isso é best-effort: nomes fantasia muito
// diferentes da razão social (ex. apelidos de mercado) podem não bater.
function normalizar(txt) {
  return String(txt || '')
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
    .replace(/\b(S\.?A\.?|SA|LTDA|HOLDING|HOLDINGS|LTD|INC|CORP|CIA|COMPANHIA|GROUP|GRUPO|CO)\b\.?/g, '')
    .replace(/[^A-Z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Prioriza a razão social oficial (BrasilAPI/Receita Federal), quando
// disponível, sobre o nome de marketing extraído do <title> do site --
// costuma casar melhor com o nome oficial usado na listagem da B3.
const razaoSocial = cnpjResp && cnpjResp.razao_social ? cnpjResp.razao_social : '';
const nomeParaComparar = razaoSocial || nomeData.nome_provavel;
const nomeNormalizado = normalizar(nomeParaComparar);

// BUG #1 (achado ao vivo, airbnb.com): comparar por substring bruta ("XP
// INC." normaliza para só "XP" depois de remover o sufixo "INC", e "XP"
// aparece como substring dentro de "EXPERIENCES") dá falso positivo.
// BUG #2 (achado ao vivo, weg.net, ao tentar corrigir o #1 com um tamanho
// mínimo de 4 caracteres): isso também bloqueia nomes curtos LEGÍTIMOS, como
// "WEG" (3 letras) -- empresas brasileiras com nome curto são comuns (WEG,
// CSN, GOL, JBS, CVC...).
//
// Fix correto: comparar por TOKEN (palavra inteira), não por substring. "XP"
// não bate com o token "EXPERIENCES" (são palavras diferentes), mas "WEG"
// bate com o token "WEG" (é a mesma palavra). Isso resolve os dois casos ao
// mesmo tempo, sem precisar de um limite arbitrário de tamanho.
function tokens(txt) {
  return normalizar(txt).split(' ').filter(Boolean);
}

const tokensBuscado = tokens(nomeParaComparar);
const tokensBuscadoSet = new Set(tokensBuscado);

let matchB3 = null;
if (tokensBuscado.length > 0) {
  for (const stock of b3Stocks) {
    const tokensCandidato = tokens(stock.name);
    if (tokensCandidato.length === 0) continue;
    const tokensCandidatoSet = new Set(tokensCandidato);
    // Todo token do candidato aparece (como palavra inteira) no nome
    // buscado, ou todo token do nome buscado aparece no candidato -- ou
    // seja, um nome é um subconjunto de palavras do outro.
    const candidatoDentroDoBuscado = tokensCandidato.every((t) => tokensBuscadoSet.has(t));
    const buscadoDentroDoCandidato = tokensBuscado.every((t) => tokensCandidatoSet.has(t));
    if (candidatoDentroDoBuscado || buscadoDentroDoCandidato) {
      matchB3 = stock;
      break;
    }
  }
}

return [{ json: {
  ...nomeData,
  razao_social_brasilapi: razaoSocial || null,
  listada_b3: !!matchB3,
  ticker: matchB3 ? matchB3.stock : null,
  nome_correspondente: matchB3 ? matchB3.name : null,
} }];

const detectado = $('Identificar CD_CVM').first().json;
const cdCvmAlvo = detectado.cd_cvm;
const items = $input.all(); // até 2 items (ano atual + ano anterior), cada um com os CSVs descompactados do ZIP da CVM

async function extrairCsvDRE(item, itemIndex) {
  const binarios = item.binary || {};
  for (const chave of Object.keys(binarios)) {
    const bin = binarios[chave];
    if (bin && bin.fileName && /DRE_con.*\.csv$/i.test(bin.fileName)) {
      // NÃO usar Buffer.from(bin.data, 'base64') diretamente -- bin.data só
      // é base64 inline quando o n8n está no modo de armazenamento binário
      // "memory". Para arquivos grandes como estes (o zip da CVM descompacta
      // para 240+ MB), a instância pode estar (ou passar a estar) em modo
      // filesystem/S3, onde bin.data é só um ID de referência -- decodificar
      // isso como base64 não dá erro, só produz lixo silenciosamente (foi
      // exatamente o que aconteceu: 0 chunks encontrados apesar dos dados
      // reais existirem). O helper abaixo funciona em qualquer modo.
      const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, chave);
      return buffer.toString('latin1');
    }
  }
  return null;
}

function hashSimples(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash);
}

const TAMANHO_CHUNK = 1000;

// Junta as linhas do DRE Consolidado (Demonstração do Resultado -- dados
// oficiais da CVM, obrigatórios por lei para toda companhia aberta) dos
// arquivos baixados (ano atual + ano anterior), filtra só a empresa
// (CD_CVM) e só a versão "ÚLTIMO" de cada linha (a própria CVM já inclui a
// coluna "PENÚLTIMO" com o comparativo do ano anterior em cada arquivo --
// pegar as duas duplicaria os mesmos números), agrupa por período de
// referência (DT_REFER) e mantém os 3 mais recentes.
const periodos = {};

if (cdCvmAlvo) {
  for (const item of items) {
    const csvTexto = await extrairCsvDRE.call(this, item, items.indexOf(item));
    if (!csvTexto) continue;

    const linhas = csvTexto.split('\n');
    const header = (linhas[0] || '').split(';').map((h) => h.trim());
    const idx = {
      dtRefer: header.indexOf('DT_REFER'),
      denom: header.indexOf('DENOM_CIA'),
      cdCvm: header.indexOf('CD_CVM'),
      ordemExerc: header.indexOf('ORDEM_EXERC'),
      cdConta: header.indexOf('CD_CONTA'),
      dsConta: header.indexOf('DS_CONTA'),
      vlConta: header.indexOf('VL_CONTA'),
    };
    if (idx.vlConta === -1) continue; // arquivo não tem o formato esperado

    for (let i = 1; i < linhas.length; i++) {
      const linha = linhas[i];
      if (!linha) continue;
      const campos = linha.split(';');
      if (campos.length <= idx.vlConta) continue;
      if ((campos[idx.cdCvm] || '').trim() !== cdCvmAlvo) continue;
      if ((campos[idx.ordemExerc] || '').trim() !== 'ÚLTIMO') continue;

      const dtRefer = campos[idx.dtRefer];
      if (!periodos[dtRefer]) {
        periodos[dtRefer] = { denom: campos[idx.denom], linhas: [] };
      }
      periodos[dtRefer].linhas.push({
        conta: campos[idx.cdConta],
        descricao: campos[idx.dsConta],
        valor: campos[idx.vlConta],
      });
    }
  }
}

const periodosOrdenados = Object.keys(periodos).sort().reverse().slice(0, 3);

function formatarValor(valorStr) {
  const n = parseFloat(valorStr);
  if (Number.isNaN(n)) return valorStr;
  // Valores no DRE da CVM vêm em milhares de reais (campo ESCALA_MOEDA=MIL).
  return `R$ ${n.toLocaleString('pt-BR')} mil`;
}

const chunksFinais = [];

for (const dtRefer of periodosOrdenados) {
  const periodo = periodos[dtRefer];
  const textoLinhas = periodo.linhas
    .map((l) => `${l.conta} ${l.descricao}: ${formatarValor(l.valor)}`)
    .join('\n');
  const textoCompleto = `Demonstração do Resultado Consolidado -- ${periodo.denom} -- período encerrado em ${dtRefer} (dados oficiais CVM):\n${textoLinhas}`;

  for (let i = 0; i < textoCompleto.length; i += TAMANHO_CHUNK) {
    const chunkIndex = Math.floor(i / TAMANHO_CHUNK);
    chunksFinais.push({ json: {
      dominio: detectado.dominio,
      session_id: detectado.session_id,
      ticker: detectado.ticker,
      url: null,
      titulo_documento: `DRE Consolidado CVM -- ${dtRefer}`,
      chunk_index: chunkIndex,
      chunk_texto: textoCompleto.slice(i, i + TAMANHO_CHUNK),
      chunk_id_ponto: hashSimples(`${detectado.dominio}|cvm-dre|${dtRefer}|${chunkIndex}`),
      sem_conteudo_real: false,
    } });
  }
}

if (chunksFinais.length === 0) {
  chunksFinais.push({ json: {
    dominio: detectado.dominio,
    session_id: detectado.session_id,
    ticker: detectado.ticker,
    url: null,
    titulo_documento: null,
    chunk_index: 0,
    chunk_texto: 'nenhum dado financeiro oficial (CVM) encontrado para esta empresa',
    chunk_id_ponto: hashSimples(`${detectado.dominio || 'sem-dominio'}|cvm-dre|sem-dados|0`),
    sem_conteudo_real: true,
  } });
}

return chunksFinais;

// Construído aqui (JS real, não numa expressao ={{ }}) pelo mesmo motivo já
// documentado no node "Montar Prompt": o parser de expressões do n8n para no
// PRIMEIRO '}}' que encontrar, e um payload JSON aninhado como este tem
// várias chaves de fechamento adjacentes -- embutir isso direto numa
// expressão trunca o JSON no meio.
const embedItems = $input.all();
const chunkItems = $('Limpar e Dividir em Chunks').all();

const resultado = embedItems.map((item, i) => {
  const embedding = (item.json.embeddings || [[]])[0];
  const chunk = chunkItems[i].json;
  const upsert_body = JSON.stringify({
    points: [{
      id: chunk.chunk_id_ponto,
      vector: embedding,
      payload: {
        dominio: chunk.dominio,
        ticker: chunk.ticker,
        url: chunk.url,
        titulo_documento: chunk.titulo_documento,
        chunk_index: chunk.chunk_index,
        chunk_texto: chunk.chunk_texto,
        sem_conteudo_real: chunk.sem_conteudo_real,
      },
    }],
  });
  return { json: { upsert_body } };
});

return resultado;

// IMPORTANTE: os items que chegam aqui (via "Merge Status Financeiro") já
// passaram pelo node de upsert do Qdrant, cujo output HTTP substitui o json
// original do item pela resposta da API ({result, status, time}) -- então
// não dá para contar "chunks reais" inspecionando esses items diretamente.
// Em vez disso, contamos direto na origem: o node "Limpar e Dividir em
// Chunks", filtrando os itens marcados como placeholder (sem_conteudo_real).
const detectado = $('Identificar Empresa Listada (B3)').first().json;

let contexto_financeiro_status;
let quantidadeChunksReais = 0;
let quantidadeChunksManuais = 0;

if (!detectado.listada_b3) {
  contexto_financeiro_status = 'Empresa não identificada como negociada na B3 (heurística de nome/ticker não encontrou correspondência) -- sem relatórios de RI/mercado disponíveis para esta análise.';
} else {
  let chunkItems = [];
  try {
    // Usa .all(0, 0) para ignorar checagem de lineage (que foi quebrado
    // intencionalmente no node "Montar Corpo do Upsert").
    chunkItems = $('Limpar e Dividir em Chunks').all(0, 0).filter(i => i.json && !i.json.sem_conteudo_real);
  } catch(e) {}
  quantidadeChunksReais = chunkItems.length;

  // Caminho paralelo à validação de dados da CVM: verifica se já existem
  // relatórios enviados manualmente (via o form de upload) para este
  // domínio na mesma collection do Qdrant.
  let pontosManuais = [];
  try {
    const respostaManual = $('Verificar Relatórios Manuais Enviados').all(0, 0)[0].json;
    pontosManuais = (respostaManual && respostaManual.result && respostaManual.result.points) || [];
  } catch(e) {}
  quantidadeChunksManuais = pontosManuais.length;

  const partes = [];
  if (quantidadeChunksReais > 0) {
    const periodosUnicos = [...new Set(chunkItems.map((i) => i.json.titulo_documento))];
    partes.push(`dados oficiais da CVM (Demonstração do Resultado Consolidado) de ${periodosUnicos.length} período(s)`);
  }
  if (quantidadeChunksManuais > 0) {
    const titulosManuais = [...new Set(pontosManuais.map((p) => p.payload.titulo_documento))];
    partes.push(`${titulosManuais.length} relatório(s) enviado(s) manualmente (${titulosManuais.join('; ')})`);
  }

  if (partes.length === 0) {
    contexto_financeiro_status = `Empresa identificada como negociada na B3 (ticker ${detectado.ticker}), mas não foi possível localizar o CD_CVM/dados oficiais desta empresa, nem há relatórios enviados manualmente para este domínio.`;
  } else {
    contexto_financeiro_status = `Empresa negociada na B3 (ticker ${detectado.ticker}). Disponível para esta análise: ${partes.join('; e ')}.`;
  }
}

return [{ json: {
  dominio: detectado.dominio,
  session_id: detectado.session_id,
  listada_b3: detectado.listada_b3,
  ticker: detectado.ticker,
  contexto_financeiro_status,
  quantidade_chunks_financeiros: quantidadeChunksReais,
  quantidade_chunks_manuais: quantidadeChunksManuais,
} }];

const detectado = $('Identificar Empresa Listada (B3)').first().json;

// Decodifica o CSV da CVM em latin1 para não corromper acentos (ex: ITAÚ)
const binarios = $input.first().binary || {};
let csvTexto = '';
const chaveBinary = Object.keys(binarios)[0];
if (chaveBinary) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, chaveBinary);
  csvTexto = buffer.toString('latin1');
} else {
  csvTexto = $json.data || $json;
}

// Reaproveita a mesma normalização/comparação por token já usada para casar
// o ticker na B3 (evita duplicar heurísticas diferentes para o mesmo tipo de
// problema -- ver "Identificar Empresa Listada (B3)").
function normalizar(txt) {
  return String(txt || '')
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
    .replace(/\b(S\.?A\.?|SA|LTDA|HOLDING|HOLDINGS|LTD|INC|CORP|CIA|COMPANHIA|GROUP|GRUPO|CO)\b\.?/g, '')
    .replace(/[^A-Z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
function tokens(txt) {
  return normalizar(txt).split(' ').filter(Boolean);
}

const cnpjAlvo = (detectado.cnpj_encontrado || '').replace(/\D/g, '');
const nomeAlvo = detectado.nome_correspondente || detectado.razao_social_brasilapi || detectado.nome_provavel || '';
const tokensAlvo = tokens(nomeAlvo);
const tokensAlvoSet = new Set(tokensAlvo);

const linhas = String(csvTexto).split('\n');
const header = (linhas[0] || '').split(';').map((h) => h.trim());
const idxCnpj = header.indexOf('CNPJ_CIA');
const idxDenom = header.indexOf('DENOM_SOCIAL');
const idxCdCvm = header.indexOf('CD_CVM');
const idxSit = header.indexOf('SIT');

let cdCvmEncontrado = null;
let nomeEncontrado = null;

// 1) match exato por CNPJ -- mais confiável que qualquer heurística de nome.
let candidatoSecundario = null;
if (cnpjAlvo) {
  for (let i = 1; i < linhas.length; i++) {
    const campos = linhas[i].split(';');
    if (campos.length <= idxCdCvm) continue;
    const cnpjLinha = (campos[idxCnpj] || '').replace(/\D/g, '');
    if (cnpjLinha === cnpjAlvo) {
      if (campos[idxSit] === 'ATIVO') {
        cdCvmEncontrado = campos[idxCdCvm];
        nomeEncontrado = campos[idxDenom];
        break;
      } else if (!candidatoSecundario) {
        candidatoSecundario = { cd: campos[idxCdCvm], nome: campos[idxDenom] };
      }
    }
  }
}
if (!cdCvmEncontrado && candidatoSecundario) {
  cdCvmEncontrado = candidatoSecundario.cd;
  nomeEncontrado = candidatoSecundario.nome;
}

// 2) fallback: match por nome (mesma lógica de token usada no match B3).
if (!cdCvmEncontrado && tokensAlvo.length > 0) {
  let candidatoSecundarioNome = null;
  for (let i = 1; i < linhas.length; i++) {
    const campos = linhas[i].split(';');
    if (campos.length <= idxCdCvm) continue;
    const tokensCandidato = tokens(campos[idxDenom]);
    if (tokensCandidato.length === 0) continue;
    const tokensCandidatoSet = new Set(tokensCandidato);
    const candidatoDentroDoAlvo = tokensCandidato.every((t) => tokensAlvoSet.has(t));
    const alvoDentroDoCandidato = tokensAlvo.every((t) => tokensCandidatoSet.has(t));
    if (candidatoDentroDoAlvo || alvoDentroDoCandidato) {
      if (campos[idxSit] === 'ATIVO') {
        cdCvmEncontrado = campos[idxCdCvm];
        nomeEncontrado = campos[idxDenom];
        break;
      } else if (!candidatoSecundarioNome) {
        candidatoSecundarioNome = { cd: campos[idxCdCvm], nome: campos[idxDenom] };
      }
    }
  }
  if (!cdCvmEncontrado && candidatoSecundarioNome) {
    cdCvmEncontrado = candidatoSecundarioNome.cd;
    nomeEncontrado = candidatoSecundarioNome.nome;
  }
}

// CD_CVM aparece sem zero à esquerda no cadastro, mas com 6 dígitos
// (zero-padded) nos arquivos de ITR -- confirmado inspecionando os dados
// reais (WEG: "5410" no cadastro, "005410" no ITR).
const cdCvmPadded = cdCvmEncontrado ? String(cdCvmEncontrado).trim().padStart(6, '0') : null;
const anoAtual = new Date().getFullYear();

return [{ json: {
  ...detectado,
  cd_cvm: cdCvmPadded,
  nome_cvm: nomeEncontrado,
  ano_atual: anoAtual,
  ano_anterior: anoAtual - 1,
} }];

const form = $('Upload Manual de Relatório PDF').first().json;
// NÃO usar $json.text aqui -- o input direto deste node vem de "Garantir
// Collection Financeira Existe (Upload)", um node HTTP cuja resposta
// substitui o json original do item (mesmo motivo já documentado em
// "Finalizar Status Financeiro"). Por isso referenciamos a origem real do
// texto extraído pelo nome, não pelo $json direto.
const textoExtraido = $('Extrair Texto do PDF Enviado').first().json.text || '';

function hashSimples(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash);
}

const TAMANHO_CHUNK = 1000;
const MAX_CHARS = 20000; // cap alto -- é um upload manual e deliberado, não uma busca automática

const dominio = String(form.dominio_empresa || '').trim().toLowerCase();
const ticker = (form.ticker_b3 || '').trim() || null;
const tituloDocumento = (form.titulo_documento || '').trim() || 'Relatório enviado manualmente';

const textoLimpo = String(textoExtraido).replace(/\s+/g, ' ').trim().slice(0, MAX_CHARS);

const chunksFinais = [];
for (let i = 0; i < textoLimpo.length; i += TAMANHO_CHUNK) {
  const chunkIndex = Math.floor(i / TAMANHO_CHUNK);
  chunksFinais.push({ json: {
    dominio,
    ticker,
    url: null,
    titulo_documento: tituloDocumento,
    chunk_index: chunkIndex,
    chunk_texto: textoLimpo.slice(i, i + TAMANHO_CHUNK),
    // Namespace "upload-manual" distinto do "cvm-dre" usado nos dados da
    // CVM -- evita qualquer colisão de ID entre as duas fontes na mesma
    // collection do Qdrant.
    chunk_id_ponto: hashSimples(`${dominio}|upload-manual|${tituloDocumento}|${chunkIndex}`),
    sem_conteudo_real: false,
    fonte: 'upload_manual',
  } });
}

return chunksFinais;

// Mesmo motivo já documentado nos outros nodes de upsert deste workflow: o
// corpo é construído aqui em JS, não numa expressão ={{ }} do node HTTP
// seguinte, porque o parser de expressões do n8n para no primeiro '}}' que
// encontrar, e um payload JSON aninhado tem várias chaves de fechamento
// adjacentes.
const embedItems = $input.all();
const chunkItems = $('Preparar Chunks do Upload Manual').all();

const resultado = embedItems.map((item, i) => {
  const embedding = (item.json.embeddings || [[]])[0];
  const chunk = chunkItems[i].json;
  const upsert_body = JSON.stringify({
    points: [{
      id: chunk.chunk_id_ponto,
      vector: embedding,
      payload: {
        dominio: chunk.dominio,
        ticker: chunk.ticker,
        url: chunk.url,
        titulo_documento: chunk.titulo_documento,
        chunk_index: chunk.chunk_index,
        chunk_texto: chunk.chunk_texto,
        sem_conteudo_real: chunk.sem_conteudo_real,
        fonte: chunk.fonte,
      },
    }],
  });
  return { json: { upsert_body } };
});

return resultado;

const form = $('Upload Manual de Relatório PDF').first().json;
const chunkItems = $('Preparar Chunks do Upload Manual').all(0, 0);

return [{ json: {
  dominio: form.dominio_empresa,
  titulo_documento: form.titulo_documento,
  quantidade_chunks: chunkItems.length,
} }];

// NÃO usar $json.dominio aqui -- o input direto deste node passou por
// "Garantir Collection Financeira Existe" (HTTP), cuja resposta substitui o
// json original do item (mesmo motivo documentado várias vezes neste
// workflow). Referenciamos a origem real dos dados pelo nome.
const dominio = $('Identificar Empresa Listada (B3)').first().json.dominio;

const corpo = {
  filter: {
    must: [
      { key: 'dominio', match: { value: dominio } },
      { key: 'fonte', match: { value: 'upload_manual' } },
    ],
  },
  limit: 50,
  with_payload: true,
};

return [{ json: { ...$json, corpo_consulta_manual: JSON.stringify(corpo) } }];
